            'id': id,
            'info': trade,
            'timestamp': timestamp,
            'datetime': this.iso8601(timestamp),
            'outcome': outcome,
            'outcomeId': assetId,
            'label': this.safeString(mkt, 'label'),
            'market': this.safeString(mkt, 'market'),
            'order': this.safeString2(trade, 'orderId', 'taker_order_id'),
            'type': undefined,
            'side': side,
            'takerOrMaker': takerOrMaker,
            'price': price,
            'amount': amount,
            'cost': undefined,
            'fee': fee,
